Ниже приведено определение шаблонного класса `Set`, который соответствует всем указанным требованиям:

```cpp
#include <iostream>
#include <set>
#include <iterator>
#include <algorithm>

template <typename T>
class Set {
private:
    std::set<T> data;

public:
    // Конструктор по умолчанию
    Set() {}

    // Конструктор с параметрами
    Set(T* arr, int size) {
        for (int i = 0; i < size; ++i) {
            data.insert(arr[i]);
        }
    }

    // Добавить один элемент в множество
    void add(const T& element) {
        data.insert(element);
    }

    // Добавить массив элементов в множество
    void add(T* elements, int size) {
        for (int i = 0; i < size; ++i) {
            data.insert(elements[i]);
        }
    }

    // Удалить элемент из множества
    void del(const T& element) {
        auto it = data.find(element);
        if (it != data.end()) {
            data.erase(it);
        }
    }

    // Проверить наличие элемента в множестве
    bool in(const T& element) const {
        return data.find(element) != data.end();
    }

    // Печать элементов множества
    void print() const {
        for (const auto& element : data) {
            std::cout << element << " ";
        }
        std::cout << std::endl;
    }

    // Оператор пересечения множеств
    Set<T> operator*(const Set<T>& other) const {
        Set<T> result;
        std::set_intersection(data.begin(), data.end(), other.data.begin(), other.data.end(),
                              std::inserter(result.data, result.data.begin()));
        return result;
    }

    // Оператор объединения множеств
    Set<T> operator+(const Set<T>& other) const {
        Set<T> result = *this;
        result.data.insert(other.data.begin(), other.data.end());
        return result;
    }
};

int main() {
    int a[] = { 1, 2, 3, 4, 5 };
    int b[] = { 3, 2, 6};
    Set<int> seti1(a, 5), seti2, seti3, seti4;
    seti2.add(b, 3);

    seti1.print(); // Выводит: 1 2 3 4 5
    seti2.print(); // Выводит: 2 3 6 
    seti3 = seti1 * seti2; // Пересечение
    seti4 = seti1 + seti2; // Объединение

    std::cout << "Intersect: ";
    seti3.print(); // Выводит: 2 3
    std::cout << "Union: ";
    seti4.print(); // Выводит: 1 2 3 4 5 6

    return 0;
}
```

Этот шаблонный класс `Set` использует для внутреннего хранения элементов контейнер `std::set` из стандартной библиотеки C++. `std::set` автоматически хранит элементы в сортированном порядке и не допускает дубликаты, что облегчает управление множествами. Класс включает методы для добавления, удаления, проверки существования элемента, а также операции для печати, пересечения и объединения множеств.

